                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" tick={{fontSize: 10}} label={{ value: 'Días Promedio', position: 'insideBottom', offset: -5, fontSize: 10 }} />
                                <YAxis dataKey="state" type="category" tick={{fontSize: 10}} width={120} />
                                <Tooltip 
                                    cursor={{fill: '#f8fafc'}}
                                    contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                                />
                                <Bar dataKey="avg" radius={[0, 4, 4, 0]} barSize={30}>
                                    {bottleneckMetrics.avgDaysPerState.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.avg > 15 ? '#f97316' : '#6366f1'} />
                                    ))}
                                </Bar>
