                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Layers size={16} className="text-indigo-500" /> Envejecimiento de Inventario Activo</h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución de documentos por tiempo transcurrido en el estado actual.</p>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={bottleneckMetrics.agingBuckets} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="state" tick={{fontSize: 10}} />
                                <YAxis tick={{fontSize: 10}} />
                                <Tooltip contentStyle={{borderRadius: '8px', border: 'none'}} />
                                <Legend />
                                <Bar dataKey="0-7 días" stackId="a" fill={AGING_COLORS['0-7 días']} />
                                <Bar dataKey="8-15 días" stackId="a" fill={AGING_COLORS['8-15 días']} />
                                <Bar dataKey="16-30 días" stackId="a" fill={AGING_COLORS['16-30 días']} />
                                <Bar dataKey="+30 días" stackId="a" fill={AGING_COLORS['+30 días']} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Activity size={16} className="text-red-500" /> Documentos Críticos (Estancados)</h3>
                <p className="text-xs text-slate-500 mb-6">Documentos con más de 15 días sin cambios de etapa. Priorice la revisión de estos ítems.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {bottleneckMetrics.stuckDocs.length === 0 ? (
                        <div className="col-span-full py-8 text-center text-slate-400">
                            <CheckCircle size={32} className="mx-auto mb-2 text-green-200" />
                            <p className="text-xs">No hay documentos estancados en el sistema.</p>
                        </div>
                    ) : bottleneckMetrics.stuckDocs.map(d => (
                        <div 
                            key={d.id} 
                            onClick={() => navigate(`/doc/${d.id}`)}
                            className="p-4 bg-slate-50 rounded-xl border border-slate-200 hover:border-indigo-300 transition-all cursor-pointer group shadow-sm flex flex-col justify-between"
                        >
                            <div>
                                <div className="flex justify-between items-start mb-2">
                                    <span className="text-[10px] font-bold text-indigo-600 uppercase bg-indigo-50 px-2 py-1 rounded border border-indigo-100">{d.project}</span>
                                    <span className={`text-[10px] font-bold px-2 py-1 rounded border ${d.daysStuck > 30 ? 'bg-red-50 text-red-600 border-red-100' : 'bg-orange-50 text-orange-600 border-orange-100'}`}>
                                        {d.daysStuck} días estancado
                                    </span>
                                </div>
                                <h4 className="text-xs font-bold text-slate-800 line-clamp-2 group-hover:text-indigo-600 leading-tight">{d.title}</h4>
                            </div>
                            <div className="flex items-center justify-between mt-4">
                                <div className="flex items-center gap-1 text-[10px] text-slate-500">
                                    <Clock size={10} />
                                    <span>Desde: {new Date(d.updatedAt).toLocaleDateString()}</span>
                                </div>
                                <div className={`text-[9px] font-bold px-1.5 py-0.5 rounded border ${STATE_CONFIG[d.state].color}`}>
                                    {STATE_CONFIG[d.state].label.split('(')[0]}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                {bottleneckMetrics.stuckDocs.length > 0 && (
                    <div className="mt-6 flex justify-center">
                        <button 
                            onClick={() => goToDashboard(bottleneckMetrics.stuckDocs.map(d => d.id))}
                            className="flex items-center gap-2 px-6 py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-all border border-indigo-100 font-bold text-xs uppercase tracking-wider shadow-sm"
                        >
                            Explorar en Dashboard <ArrowRight size={14} />
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
